from pathlib import Path
import shutil

root = Path('shaders')

category = {}

def put(names, folder):
    for n in names:
        category[n] = folder

all_files = [p.name for p in root.iterdir() if p.is_file() and p.name != 'AGENTS.md']

# Runtime/support and diagnostics.
for n in all_files:
    if n.startswith('diag_') or n.startswith('test_'):
        category[n] = 'diagnostic'
for n in ['common.vert', 'palette_tex.glsl', 'post_glow_h.frag', 'post_glow_v.frag', 'ink_sparkle.frag']:
    category[n] = 'runtime'

# Legacy/demo shaders without _gpu suffix.
for n in [
    'mandelbrot.frag', 'julia.frag', 'burning_ship.frag', 'phoenix.frag',
    'mandelbulb.frag', 'mandelbrot_simple.frag', 'mandelbrot_et.frag',
    'mandelbrot_hardgrad.frag', 'mandelbrot_tex.frag', 'mandel_step_escape.frag',
    'mandel_step_smooth.frag', 'mandelbrot_df2.frag',
]:
    category[n] = 'legacy'

# Name-based coherent domains.
ifs_prefixes = (
    'sierpinski_', 'koch_', 'dragon_', 'golden_dragon', 'twin_dragon', 'terdragon',
    'barnsley_', 'cyclosorus_', 'pythagorean_', 'hilbert_', 'peano_', 'gosper_',
    'levy_', 'menger_', 'vicsek_', 'penrose_', 'fibonacci_', 'rauzy_', 'pinwheel_',
    'chair_', 'z_order_', 'greek_cross', 'cantor_', 'apollonian_', 'ford_',
    'steiner_', 'cesaro_', 'fractal_canopy', 'hat_', 'spectre_', 'sphinx_',
    'cayley_', 'mcworter_', 'ammann_', 'moore_curve', 'jerusalem_', 'pola_',
    'hexaflake', 'pentaflake', 'kifs_', 'kleinian_', 'pseudo_kleinian',
    'inversive_',
)
cellular_prefixes = (
    'wolfram_', 'langton_', 'sandpile', 'dla_', 'forest_fire', 'percolation',
    'turmite', 'wireworld', 'brian_brain', 'highlife', 'day_night', 'eden_',
    'gray_scott', 'dielectric_', 'lichtenberg_',
)
strange_names = {
    'clifford', 'peter_de_jong', 'svensson', 'gumowski_mira', 'arnold_cat',
    'standard_map', 'zaslavsky', 'kicked_rotator', 'chua', 'sprott', 'burke_shaw',
    'arneodo', 'thomas_attractor', 'four_wing', 'lorenz_2d', 'rossler_2d',
    'dadras', 'chen', 'lu_chen', 'halvorsen', 'scroll_waves', 'rikitake', 'aizawa',
    'rabinovich_fabrikant', 'nose_hoover', 'moore_spiegel', 'hadley', 'genesio_tesi',
    'liu_chen', 'newton_leipnik', 'bouali', 'dequan_li', 'coullet', 'sakarya',
    'qi_chen', 'yu_wang', 'zhou_chen', 'tsucs', 'rayleigh_benard', 'robinson',
    'globo_toroid', 'tamari', 'wang_sun_cang', 'henon', 'tinkerbell',
    'gingerbreadman', 'lozi', 'duffing', 'ikeda', 'hopalong', 'pickover',
    'bogdanov_map', 'rucklidge', 'shimizu_morioka', 'chen_lee',
}
three_d_prefixes = (
    '3d_', 'mandelbulb', 'mandelbox', 'quaternion_', 'dual_quaternion', 'tessarine_',
    'split_complex', 'dual_complex', 'bicomplex', 'hypercomplex_', 'menger_3d',
)
lyap_names = {'lyapunov_gpu.frag','logistic_lyapunov_gpu.frag','circle_map_lyapunov_gpu.frag','sine_map_lyapunov_gpu.frag','tent_map_gpu.frag','feigenbaum_gpu.frag','gauss_map_gpu.frag'}
trig_prefixes = ('sine_', 'cosine_', 'tangent_', 'sinh_', 'cosh_', 'tanh_', 'cosecant_', 'cotangent_', 'secant_', 'exponential_', 'zeta', 'dirichlet_', 'weierstrass_', 'jacobi_', 'mittag_', 'superexponential', 'transcendental_', 'tetration')
newton_tokens = ('newton', 'halley', 'householder', 'schroeder', 'steffensen', 'durand_', 'ehrlich_', 'jarratt', 'muller', 'neta_', 'noor_', 'ostrowski', 'picard_', 'super_halley', 'traub_')
kaleidoscope_prefix = 'kaleidoscope_'

for n in all_files:
    if n in category:
        continue
    stem = n[:-5] if n.endswith('.frag') else n
    if n in lyap_names:
        category[n] = 'lyapunov_and_stability'
    elif n.startswith(kaleidoscope_prefix):
        category[n] = 'kaleidoscopes'
    elif n.startswith(ifs_prefixes):
        category[n] = 'ifs_and_geometric'
    elif n.startswith(cellular_prefixes):
        category[n] = 'cellular_and_stochastic'
    elif n.startswith(three_d_prefixes):
        category[n] = '3d_and_hypercomplex'
    elif any(stem.startswith(s) for s in strange_names) or stem.startswith('sprott_'):
        category[n] = 'strange_attractors'
    elif n.startswith(trig_prefixes):
        category[n] = 'trigonometric_and_transcendental'
    elif any(tok in n for tok in newton_tokens):
        category[n] = 'root_finding'
    else:
        category[n] = 'escape_time_family'

missing = sorted(set(all_files) - set(category))
if missing:
    raise SystemExit(f'missing categories: {missing}')

# Move files and build replacement map.
replacements = {}
for name, folder in sorted(category.items()):
    src = root / name
    if not src.exists():
        continue
    dst_dir = root / folder
    dst_dir.mkdir(exist_ok=True)
    dst = dst_dir / name
    if dst.exists():
        raise SystemExit(f'destination exists: {dst}')
    shutil.move(str(src), str(dst))
    replacements[f'shaders/{name}'] = f'shaders/{folder}/{name}'

# Update textual references in first-party project files. Do not touch .git/build/opensource.
scan_roots = [Path('pubspec.yaml'), Path('lib'), Path('test'), Path('integration_test'), Path('scripts'), Path('shaders/AGENTS.md')]
text_suffixes = {'.dart', '.yaml', '.yml', '.md', '.sh', '.json'}
for base in scan_roots:
    paths = [base] if base.is_file() else [p for p in base.rglob('*') if p.is_file()]
    for path in paths:
        if path.suffix and path.suffix not in text_suffixes:
            continue
        try:
            text = path.read_text()
        except UnicodeDecodeError:
            continue
        new = text
        for old, repl in replacements.items():
            new = new.replace(old, repl)
        if new != text:
            path.write_text(new)

print('Moved', len(replacements), 'shader files into', len(set(category.values())), 'subfolders')
for folder in sorted(set(category.values())):
    print(folder, sum(1 for v in category.values() if v == folder))

