python3 - <<'PY'
from pathlib import Path
import subprocess,re
# basenames of deleted root shader files from git status
out=subprocess.check_output(['git','status','--short'], text=True)
moved=[]
for line in out.splitlines():
    if line.startswith(' D shaders/'):
        moved.append(Path(line[3:]).name)
print('moved',len(moved))
files=[]
for base in ['pubspec.yaml','lib','test','integration_test','scripts']:
    p=Path(base)
    if p.is_file(): files.append(p)
    elif p.exists(): files += [q for q in p.rglob('*') if q.is_file()]
bad=[]
for f in files:
    try: text=f.read_text()
    except UnicodeDecodeError: continue
    for name in moved:
        old=f'shaders/{name}'
        if old in text:
            bad.append((str(f), old))
            break
print('stale moved-root refs', len(bad))
for x in bad[:50]: print(x)
